class Solution {
public:
    int maxScore(vector<int>& nums) {
        int n = nums.size() / 2;
        vector<int> state(1 << nums.size(), -1);
        return dfs(nums, state, (1 << nums.size()) - 1, n);
    }

    int dfs(vector<int>& nums, vector<int>& state, int mask, int n) {
        if (state[mask] != -1) return state[mask];
        if (n == 0) return state[mask] = 0;

        int res = 0;
        vector<int> indices;
        for (int i = 0; i < nums.size(); ++i) {
            if ((mask >> i) & 1) indices.push_back(i);
        }

        for (int i = 0; i < indices.size(); ++i) {
            for (int j = i + 1; j < indices.size(); ++j) {
                int x = nums[indices[i]], y = nums[indices[j]];
                int new_mask = mask ^ (1 << indices[i]) ^ (1 << indices[j]);
                res = max(res, n * gcd(x, y) + dfs(nums, state, new_mask, n - 1));
            }
        }
        return state[mask] = res;
    }

    int gcd(int x, int y) {
        if (y == 0) return x;
        return gcd(y, x % y);
    }
};
